import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def path_score(truck_pos, customer):
        distance_to_customer = np.linalg.norm(truck_pos - customer)
        potential_routes = [np.linalg.norm(depot_pos - customer) + distance_to_customer]
        for other_truck in all_truck_pos:
            if not np.array_equal(other_truck, truck_pos):
                potential_routes.append(np.linalg.norm(other_truck - customer))
        return distance_to_customer + np.std(potential_routes)

    best_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        score = path_score(cur_truck_pos, customer)
        if score < best_score:
            best_score = score
            best_node = i

    if best_score == float('inf'):
        return None

    return best_node
